mapper.select:
SELECT id, name, birthday, birth_cd, sex
FROM citylab_member
where id = #{id}

SELECT a.id, a.name, a.birthday, a.birth_cd, a.sex, a.phone, b.concern1, b.concern2, c.consult_count FROM citylab_member a LEFT JOIN ( SELECT *, ROW_NUMBER() OVER(PARTITION BY userkey ORDER BY consult_date DESC) AS rn FROM tb_consult_info ) b ON a.id = b.userkey AND b.rn = 1 LEFT JOIN ( SELECT userkey, COUNT(*) AS consult_count FROM tb_consult_info GROUP BY userkey ) c ON a.id = c.userkey
AND a.name = #{name}
AND (YEAR(CURDATE()) - YEAR(a.birthday)) - CASE WHEN DATE_FORMAT(CURDATE(), '%m%d') < DATE_FORMAT(a.birthday, '%m%d') THEN 1 ELSE 0 END) = #{age}
